package me.nethma.bookdiary;

import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.text.Editable;
import android.view.ViewGroup;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

import me.nethma.bookdiary.database.AppDatabase;
import me.nethma.bookdiary.database.Book;
import me.nethma.bookdiary.utils.SessionManager;
import androidx.fragment.app.Fragment;

    // ── Views ─────────────────────────────────────────────────────────────────
    private RecyclerView       rvFavorites;
    private RecyclerView       rvAllBooks;
    private AllBooksAdapter     allBooksAdapter;

    // ── State ─────────────────────────────────────────────────────────────────
    private String selectedCategory = "All";
    private String searchQuery      = "";
    private static final String[] CATEGORIES =
            {"All", "Fiction", "Science", "Mystery", "History"};

    @Nullable @Override

        // Set up adapters
        favoriteAdapter = new FavoriteBookAdapter(new FavoriteBookAdapter.OnBookClickListener() {
            @Override public void onBookClick(Book book)      { openBookDetail(book); }
            @Override public void onFavoriteToggle(Book book) { toggleFavorite(book); }
        });

        allBooksAdapter = new AllBooksAdapter(new AllBooksAdapter.OnBookClickListener() {
            @Override public void onBookClick(Book book)      { openBookDetail(book); }
            @Override public void onFavoriteToggle(Book book) { toggleFavorite(book); }
        });

        rvFavorites.setLayoutManager(
                new LinearLayoutManager(requireContext(),
                        LinearLayoutManager.HORIZONTAL, false));
        rvFavorites.setAdapter(favoriteAdapter);

        rvAllBooks.setLayoutManager(new LinearLayoutManager(requireContext()));
        rvAllBooks.setAdapter(allBooksAdapter);
        rvAllBooks.setNestedScrollingEnabled(false);

        // Header buttons
        view.findViewById(R.id.btn_notifications).setOnClickListener(v ->
                Toast.makeText(requireContext(),
                        "Notifications coming soon!", Toast.LENGTH_SHORT).show());

        view.findViewById(R.id.btn_filter).setOnClickListener(v ->
                Toast.makeText(requireContext(),
                        "Advanced filter coming soon!", Toast.LENGTH_SHORT).show());

        // "See all" → Favourites screen
        view.findViewById(R.id.tv_see_all).setOnClickListener(v ->
                Toast.makeText(requireContext(),
                        "Favourites screen coming soon!", Toast.LENGTH_SHORT).show());

        // Search
        etSearch.addTextChangedListener(new TextWatcher() {
            @Override public void beforeTextChanged(CharSequence s, int a, int b, int c) {}
            @Override public void onTextChanged(CharSequence s, int a, int b, int c) {}
            @Override
            public void afterTextChanged(Editable s) {
                searchQuery = s.toString().trim();
                loadBooks();
            }
        });

        // Category chips
        buildCategoryChips();

        // Seed demo data then load
        seedSampleDataThenLoad();

        return view;
    }

    @Override
    public void onResume() {
        super.onResume();   // BaseFragment applies accent colour
        loadBooks();
        // Refresh chip styles with potentially updated accent colour
        refreshChipStyles();
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Category chips
    // ─────────────────────────────────────────────────────────────────────────

    private void buildCategoryChips() {
        chipContainer.removeAllViews();
        int accent = accentColor();
        for (String cat : CATEGORIES) {
            TextView chip = (TextView) LayoutInflater.from(requireContext())
                    .inflate(R.layout.item_category_chip, chipContainer, false);
            chip.setText(cat);
            applyChipStyle(chip, cat.equals(selectedCategory), accent);
            chip.setOnClickListener(v -> {
                selectedCategory = cat;
                refreshChipStyles();
                loadBooks();
            });
            chipContainer.addView(chip);
        }
    }

    private void refreshChipStyles() {
        if (chipContainer == null) return;
        int accent = accentColor();
        for (int i = 0; i < chipContainer.getChildCount(); i++) {
            TextView chip = (TextView) chipContainer.getChildAt(i);
            applyChipStyle(chip, CATEGORIES[i].equals(selectedCategory), accent);
        }
    }

    private void applyChipStyle(TextView chip, boolean active, int accent) {
        float density = getResources().getDisplayMetrics().density;
        GradientDrawable bg = new GradientDrawable();
        bg.setShape(GradientDrawable.RECTANGLE);
        bg.setCornerRadius(50 * density);

        if (active) {
            bg.setColor(accent);
            chip.setBackground(bg);
            chip.setTextColor(0xFFFFFFFF);
        } else {
            boolean isDark = (requireContext().getResources().getConfiguration().uiMode
                    & Configuration.UI_MODE_NIGHT_MASK) == Configuration.UI_MODE_NIGHT_YES;
            bg.setColor(isDark ? 0xFF1E293B : 0xFFE2E8F0);
            chip.setBackground(bg);
            chip.setTextColor(isDark ? 0xFF94A3B8 : 0xFF64748B);
        }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Data loading
    // ─────────────────────────────────────────────────────────────────────────

    /** Load (and filter) books from the database on a background thread. */
    private void loadBooks() {
        int    userId   = sessionManager.getUserId();
        String query    = searchQuery;
        String category = selectedCategory;

        executor.execute(() -> {
            List<Book> allBooks  = db.bookDao().searchAndFilter(userId, query, category);
            List<Book> favorites = db.bookDao().getFavoriteBooks(userId);

            mainHandler.post(() -> {
                if (!isAdded()) return;

                // Favourites section
                favoriteAdapter.setBooks(favorites);
                boolean hasFavorites = !favorites.isEmpty();
                rvFavorites.setVisibility(
                        hasFavorites ? View.VISIBLE : View.GONE);
                emptyFavoritesContainer.setVisibility(
                        hasFavorites ? View.GONE : View.VISIBLE);

                // All books section
                allBooksAdapter.setBooks(allBooks);
                boolean hasBooks = !allBooks.isEmpty();
                rvAllBooks.setVisibility(
                        hasBooks ? View.VISIBLE : View.GONE);
                emptyBooksContainer.setVisibility(
                        hasBooks ? View.GONE : View.VISIBLE);
            });
        });
    }

    /** Toggle the isFavorite flag for a book and refresh the UI. */
    private void toggleFavorite(Book book) {
        executor.execute(() -> {
            book.isFavorite = !book.isFavorite;
            db.bookDao().update(book);
            mainHandler.post(() -> {
                if (!isAdded()) return;
                loadBooks();
            });
        });
    }

    private void openBookDetail(Book book) {
        // TODO: launch BookDetailActivity, passing book.id
        Toast.makeText(requireContext(), book.title, Toast.LENGTH_SHORT).show();
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Sample data seeding (first launch only)
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * Seeds a handful of demo books when the user has no books yet.
     * Called once on first launch so the Home screen is never blank.
     */
    private void seedSampleDataThenLoad() {
        int userId = sessionManager.getUserId();

        executor.execute(() -> {
            if (db.bookDao().getBookCount(userId) == 0) {
                long now = System.currentTimeMillis();

                db.bookDao().insert(book(userId, "The Great Gatsby",
                        "F. Scott Fitzgerald", "Fiction",  4.8f, true,  now - days(7)));
                db.bookDao().insert(book(userId, "Midnight Library",
                        "Matt Haig",          "Fiction",  4.5f, true,  now - days(5)));
                db.bookDao().insert(book(userId, "Circe",
                        "Madeline Miller",    "Fiction",  4.9f, true,  now - days(3)));
                db.bookDao().insert(book(userId, "Project Hail Mary",
                        "Andy Weir",          "Science",  4.0f, false, now - days(2)));
                db.bookDao().insert(book(userId, "Norwegian Wood",
                        "Haruki Murakami",    "Fiction",  5.0f, false, now - days(1)));
                db.bookDao().insert(book(userId, "The Alchemist",
                        "Paulo Coelho",       "History",  4.3f, true,  now));
            }
            mainHandler.post(() -> {
                if (isAdded()) loadBooks();
            });
        });
    }
}

    /** Helper: create a Book entity with all required fields. */
    private static Book book(int userId, String title, String author,
                             String category, float rating,
                             boolean fav, long dateAdded) {
        Book b = new Book();
        b.userId    = userId;
        b.title     = title;
        b.author    = author;
        b.category  = category;
        b.rating    = rating;
        b.isFavorite = fav;
        b.dateAdded = dateAdded;
        return b;
    }

    private static long days(int n) {
        return (long) n * 24 * 60 * 60 * 1000;
    }
}

package me.nethma.bookdiary;

import android.content.res.Configuration;
import android.graphics.drawable.GradientDrawable;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.text.Editable;
import android.text.TextWatcher;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

import me.nethma.bookdiary.database.AppDatabase;
import me.nethma.bookdiary.database.Book;
import me.nethma.bookdiary.utils.SessionManager;

/**
 * Home Dashboard Fragment — displays favourite books (horizontal scroll)
 * and all books (vertical list) with live search + category filtering.
 */
public class HomeFragment extends BaseFragment {

    // ── Views ─────────────────────────────────────────────────────────────────
    private RecyclerView       rvFavorites;
    private RecyclerView       rvAllBooks;
    private EditText           etSearch;
    private LinearLayout       chipContainer;
    private View               emptyFavoritesContainer;
    private View               emptyBooksContainer;

    // ── Adapters ──────────────────────────────────────────────────────────────
    private FavoriteBookAdapter favoriteAdapter;
    private AllBooksAdapter     allBooksAdapter;

    // ── State ─────────────────────────────────────────────────────────────────
    private String selectedCategory = "All";
    private String searchQuery      = "";
    private static final String[] CATEGORIES =
            {"All", "Fiction", "Science", "Mystery", "History"};

    // ── Threading ─────────────────────────────────────────────────────────────
    private final ExecutorService executor    = Executors.newSingleThreadExecutor();
    private final Handler         mainHandler = new Handler(Looper.getMainLooper());

    // ── Dependencies ──────────────────────────────────────────────────────────
    private SessionManager sessionManager;
    private AppDatabase    db;

    // ─────────────────────────────────────────────────────────────────────────
    // Fragment lifecycle
    // ─────────────────────────────────────────────────────────────────────────

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater,
                             @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {

        View view = inflater.inflate(R.layout.fragment_home, container, false);

        sessionManager = new SessionManager(requireContext());
        db = AppDatabase.getInstance(requireContext());

        // Bind views
        rvFavorites             = view.findViewById(R.id.rv_favorites);
        rvAllBooks              = view.findViewById(R.id.rv_all_books);
        etSearch                = view.findViewById(R.id.et_search);
        chipContainer           = view.findViewById(R.id.chip_container);
        emptyFavoritesContainer = view.findViewById(R.id.empty_favorites_container);
        emptyBooksContainer     = view.findViewById(R.id.empty_books_container);

        // Set up adapters
        favoriteAdapter = new FavoriteBookAdapter(new FavoriteBookAdapter.OnBookClickListener() {
            @Override public void onBookClick(Book book)      { openBookDetail(book); }
            @Override public void onFavoriteToggle(Book book) { toggleFavorite(book); }
        });

        allBooksAdapter = new AllBooksAdapter(new AllBooksAdapter.OnBookClickListener() {
            @Override public void onBookClick(Book book)      { openBookDetail(book); }
            @Override public void onFavoriteToggle(Book book) { toggleFavorite(book); }
        });

        rvFavorites.setLayoutManager(
                new LinearLayoutManager(requireContext(),
                        LinearLayoutManager.HORIZONTAL, false));
        rvFavorites.setAdapter(favoriteAdapter);

        rvAllBooks.setLayoutManager(new LinearLayoutManager(requireContext()));
        rvAllBooks.setAdapter(allBooksAdapter);
        rvAllBooks.setNestedScrollingEnabled(false);

        // Header buttons
        view.findViewById(R.id.btn_notifications).setOnClickListener(v ->
                Toast.makeText(requireContext(),
                        "Notifications coming soon!", Toast.LENGTH_SHORT).show());

        view.findViewById(R.id.btn_filter).setOnClickListener(v -> {
            if (getActivity() instanceof MainActivity) {
                ((MainActivity) getActivity()).navigateToSearch(searchQuery);
            }
        });

        // "See all" → SearchFragment
        view.findViewById(R.id.tv_see_all).setOnClickListener(v -> {
            if (getActivity() instanceof MainActivity) {
                ((MainActivity) getActivity()).navigateToSearch("");
            }
        });

        // Search
        etSearch.addTextChangedListener(new TextWatcher() {
            @Override public void beforeTextChanged(CharSequence s, int a, int b, int c) {}
            @Override public void onTextChanged(CharSequence s, int a, int b, int c) {}
            @Override
            public void afterTextChanged(Editable s) {
                searchQuery = s.toString().trim();
                loadBooks();
            }
        });

        // Category chips
        buildCategoryChips();

        // Seed demo data then load
        seedSampleDataThenLoad();

        return view;
    }

    @Override
    public void onResume() {
        super.onResume();   // BaseFragment applies accent colour
        loadBooks();
        // Refresh chip styles with potentially updated accent colour
        refreshChipStyles();
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Category chips
    // ─────────────────────────────────────────────────────────────────────────

    private void buildCategoryChips() {
        chipContainer.removeAllViews();
        int accent = accentColor();
        for (String cat : CATEGORIES) {
            TextView chip = (TextView) LayoutInflater.from(requireContext())
                    .inflate(R.layout.item_category_chip, chipContainer, false);
            chip.setText(cat);
            applyChipStyle(chip, cat.equals(selectedCategory), accent);
            chip.setOnClickListener(v -> {
                selectedCategory = cat;
                refreshChipStyles();
                loadBooks();
            });
            chipContainer.addView(chip);
        }
    }

    private void refreshChipStyles() {
        if (chipContainer == null) return;
        int accent = accentColor();
        for (int i = 0; i < chipContainer.getChildCount(); i++) {
            TextView chip = (TextView) chipContainer.getChildAt(i);
            applyChipStyle(chip, CATEGORIES[i].equals(selectedCategory), accent);
        }
    }

    private void applyChipStyle(TextView chip, boolean active, int accent) {
        float density = getResources().getDisplayMetrics().density;
        GradientDrawable bg = new GradientDrawable();
        bg.setShape(GradientDrawable.RECTANGLE);
        bg.setCornerRadius(50 * density);

        if (active) {
            bg.setColor(accent);
            chip.setBackground(bg);
            chip.setTextColor(0xFFFFFFFF);
        } else {
            boolean isDark = (requireContext().getResources().getConfiguration().uiMode
                    & Configuration.UI_MODE_NIGHT_MASK) == Configuration.UI_MODE_NIGHT_YES;
            bg.setColor(isDark ? 0xFF1E293B : 0xFFE2E8F0);
            chip.setBackground(bg);
            chip.setTextColor(isDark ? 0xFF94A3B8 : 0xFF64748B);
        }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Data loading
    // ─────────────────────────────────────────────────────────────────────────

    /** Load (and filter) books from the database on a background thread. */
    private void loadBooks() {
        int    userId   = sessionManager.getUserId();
        String query    = searchQuery;
        String category = selectedCategory;

        executor.execute(() -> {
            List<Book> allBooks  = db.bookDao().searchAndFilter(userId, query, category);
            List<Book> favorites = db.bookDao().getFavoriteBooks(userId);

            mainHandler.post(() -> {
                if (!isAdded()) return;

                // Favourites section
                favoriteAdapter.setBooks(favorites);
                boolean hasFavorites = !favorites.isEmpty();
                rvFavorites.setVisibility(
                        hasFavorites ? View.VISIBLE : View.GONE);
                emptyFavoritesContainer.setVisibility(
                        hasFavorites ? View.GONE : View.VISIBLE);

                // All books section
                allBooksAdapter.setBooks(allBooks);
                boolean hasBooks = !allBooks.isEmpty();
                rvAllBooks.setVisibility(
                        hasBooks ? View.VISIBLE : View.GONE);
                emptyBooksContainer.setVisibility(
                        hasBooks ? View.GONE : View.VISIBLE);
            });
        });
    }

    /** Toggle the isFavorite flag for a book and refresh the UI. */
    private void toggleFavorite(Book book) {
        executor.execute(() -> {
            book.isFavorite = !book.isFavorite;
            db.bookDao().update(book);
            mainHandler.post(() -> {
                if (!isAdded()) return;
                loadBooks();
            });
        });
    }

    private void openBookDetail(Book book) {
        // TODO: launch BookDetailActivity, passing book.id
        Toast.makeText(requireContext(), book.title, Toast.LENGTH_SHORT).show();
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Sample data seeding (first launch only)
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * Seeds a handful of demo books when the user has no books yet.
     * Called once on first launch so the Home screen is never blank.
     */
    private void seedSampleDataThenLoad() {
        int userId = sessionManager.getUserId();

        executor.execute(() -> {
            if (db.bookDao().getBookCount(userId) == 0) {
                long now = System.currentTimeMillis();

                db.bookDao().insert(book(userId, "The Great Gatsby",
                        "F. Scott Fitzgerald", "Fiction",  4.8f, true,  now - days(7)));
                db.bookDao().insert(book(userId, "Midnight Library",
                        "Matt Haig",          "Fiction",  4.5f, true,  now - days(5)));
                db.bookDao().insert(book(userId, "Circe",
                        "Madeline Miller",    "Fiction",  4.9f, true,  now - days(3)));
                db.bookDao().insert(book(userId, "Project Hail Mary",
                        "Andy Weir",          "Science",  4.0f, false, now - days(2)));
                db.bookDao().insert(book(userId, "Norwegian Wood",
                        "Haruki Murakami",    "Fiction",  5.0f, false, now - days(1)));
                db.bookDao().insert(book(userId, "The Alchemist",
                        "Paulo Coelho",       "History",  4.3f, true,  now));
            }
            mainHandler.post(() -> {
                if (isAdded()) loadBooks();
            });
        });
    }

    /** Helper: create a Book entity with all required fields. */
    private static Book book(int userId, String title, String author,
                             String category, float rating,
                             boolean fav, long dateAdded) {
        Book b = new Book();
        b.userId    = userId;
        b.title     = title;
        b.author    = author;
        b.category  = category;
        b.rating    = rating;
        b.isFavorite = fav;
        b.dateAdded = dateAdded;
        return b;
    }

    private static long days(int n) {
        return (long) n * 24 * 60 * 60 * 1000;
    }
}

package me.nethma.bookdiary;

import android.content.Intent;
import android.content.res.ColorStateList;
import android.graphics.drawable.GradientDrawable;
import android.os.Bundle;
import android.widget.FrameLayout;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.TextView;

import androidx.activity.EdgeToEdge;
import androidx.core.graphics.Insets;
import androidx.core.view.ViewCompat;
import androidx.core.view.WindowInsetsCompat;
import androidx.fragment.app.Fragment;
import androidx.fragment.app.FragmentContainerView;
import androidx.fragment.app.FragmentTransaction;

import me.nethma.bookdiary.utils.NotificationHelper;
import me.nethma.bookdiary.utils.NotificationScheduler;
import me.nethma.bookdiary.utils.SessionManager;
import me.nethma.bookdiary.utils.ThemePrefsManager;

public class MainActivity extends BaseActivity {

    // COLOR_ACTIVE is loaded from ThemePrefsManager at runtime
    private int COLOR_ACTIVE;
    private static final int COLOR_INACTIVE = 0xFF64748B;

    private FragmentContainerView fragmentContainer;
    private LinearLayout bottomNav;
    private SessionManager sessionManager;

    // Nav items
    private LinearLayout navHome, navSearch, navAdd, navDiary, navProfile;
    private ImageView icHome, icSearch, icDiary, icProfile;
    private TextView tvHome, tvSearch, tvAdd, tvDiary, tvProfile;

    // Add button specific views
    private FrameLayout addBtnBg;
    private ImageView icAdd;

    private int selectedNavId = R.id.nav_home;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        EdgeToEdge.enable(this);
        setContentView(R.layout.activity_main);

        // Load accent colour from prefs
        COLOR_ACTIVE = ThemePrefsManager.getAccentColor(this);

        fragmentContainer = findViewById(R.id.fragment_container);
        bottomNav         = findViewById(R.id.bottom_nav);
        sessionManager    = new SessionManager(this);

        // Apply insets
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.main), (v, insets) -> {
            Insets systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars());
            // Bottom nav: bottom padding = system nav bar
            bottomNav.setPadding(
                    bottomNav.getPaddingLeft(),
                    bottomNav.getPaddingTop(),
                    bottomNav.getPaddingRight(),
                    systemBars.bottom
            );
            // Fragment container: top = status bar, bottom = nav bar + bottom nav height
            fragmentContainer.setPadding(
                    systemBars.left,
                    systemBars.top,
                    systemBars.right,
                    systemBars.bottom + getResources().getDimensionPixelSize(R.dimen.bottom_nav_height)
            );
            return insets;
        });

        bindNavViews();
        applyAccentToAddButton(); // set accent circle on add button immediately

        // Create notification channels and schedule background workers
        NotificationHelper.createNotificationChannels(this);
        NotificationScheduler.scheduleAll(this);

        if (savedInstanceState == null) {
            loadFragment(new HomeFragment(), false);
        }
        setNavSelected(R.id.nav_home);

        navHome.setOnClickListener(v    -> selectTab(R.id.nav_home,    new HomeFragment()));
        navSearch.setOnClickListener(v  -> selectTab(R.id.nav_search,  new SearchFragment()));
        navAdd.setOnClickListener(v     -> selectTab(R.id.nav_add,     new AddFragment()));
        navDiary.setOnClickListener(v   -> selectTab(R.id.nav_diary,   new DiaryFragment()));
        navProfile.setOnClickListener(v -> selectTab(R.id.nav_profile, new ProfileFragment()));
    }

    @Override
    protected void onResume() {
        super.onResume(); // BaseActivity scans the full view tree
        // Refresh nav bar active colour (set programmatically, not via XML)
        COLOR_ACTIVE = ThemePrefsManager.getAccentColor(this);
        setNavSelected(selectedNavId);
        // Apply accent to the floating add button
        applyAccentToAddButton();
    }

    private void applyAccentToAddButton() {
        int accent = ThemePrefsManager.getAccentColor(this);

        // Recolor the FrameLayout background border stroke with accent/20
        if (addBtnBg != null && addBtnBg.getBackground() instanceof GradientDrawable) {
            GradientDrawable bg = (GradientDrawable) addBtnBg.getBackground().mutate();
            bg.setStroke(2, (accent & 0x00FFFFFF) | 0x33000000);
        }

        if (icAdd == null) return;

        // Draw an accent-colored circle as the ImageView background
        // and show only the white plus on top — this way accent changes are visible
        // without the plus disappearing (which happens when tinting the full circle+plus vector)
        GradientDrawable accentCircle = new GradientDrawable();
        accentCircle.setShape(GradientDrawable.OVAL);
        accentCircle.setColor(accent);
        icAdd.setBackground(accentCircle);
        icAdd.setPadding(10, 10, 10, 10);

        // Use a white-plus-only icon (no circle path) — tint cleared
        icAdd.setImageTintList(null);
        icAdd.setImageResource(R.drawable.ic_add_plus_white);
    }

    private void bindNavViews() {
        navHome    = findViewById(R.id.nav_home);
        navSearch  = findViewById(R.id.nav_search);
        navAdd     = findViewById(R.id.nav_add);
        navDiary   = findViewById(R.id.nav_diary);
        navProfile = findViewById(R.id.nav_profile);

        icHome    = findViewById(R.id.ic_home);
        icSearch  = findViewById(R.id.ic_search);
        icDiary   = findViewById(R.id.ic_diary);
        icProfile = findViewById(R.id.ic_profile);

        addBtnBg  = findViewById(R.id.add_btn_bg);
        icAdd     = findViewById(R.id.ic_add);

        tvHome    = findViewById(R.id.tv_home);
        tvSearch  = findViewById(R.id.tv_search);
        tvAdd     = findViewById(R.id.tv_add);
        tvDiary   = findViewById(R.id.tv_diary);
        tvProfile = findViewById(R.id.tv_profile);
    }

    private void selectTab(int navId, Fragment fragment) {
        if (selectedNavId == navId) return;
        selectedNavId = navId;
        setNavSelected(navId);
        loadFragment(fragment, true);
    }

    /** Update icon tints and label colors to reflect the selected tab */
    private void setNavSelected(int navId) {
        // Reset all to inactive
        icHome.setImageTintList(ColorStateList.valueOf(COLOR_INACTIVE));
        icSearch.setImageTintList(ColorStateList.valueOf(COLOR_INACTIVE));
        icDiary.setImageTintList(ColorStateList.valueOf(COLOR_INACTIVE));
        icProfile.setImageTintList(ColorStateList.valueOf(COLOR_INACTIVE));

        tvHome.setTextColor(COLOR_INACTIVE);
        tvSearch.setTextColor(COLOR_INACTIVE);
        tvAdd.setTextColor(COLOR_INACTIVE);
        tvDiary.setTextColor(COLOR_INACTIVE);
        tvProfile.setTextColor(COLOR_INACTIVE);

        // Activate selected
        if (navId == R.id.nav_home) {
            icHome.setImageTintList(ColorStateList.valueOf(COLOR_ACTIVE));
            tvHome.setTextColor(COLOR_ACTIVE);
        } else if (navId == R.id.nav_search) {
            icSearch.setImageTintList(ColorStateList.valueOf(COLOR_ACTIVE));
            tvSearch.setTextColor(COLOR_ACTIVE);
        } else if (navId == R.id.nav_add) {
            tvAdd.setTextColor(COLOR_ACTIVE);
            // Add icon is always primary color (filled svg), no tint needed
        } else if (navId == R.id.nav_diary) {
            icDiary.setImageTintList(ColorStateList.valueOf(COLOR_ACTIVE));
            tvDiary.setTextColor(COLOR_ACTIVE);
        } else if (navId == R.id.nav_profile) {
            icProfile.setImageTintList(ColorStateList.valueOf(COLOR_ACTIVE));
            tvProfile.setTextColor(COLOR_ACTIVE);
        }
    }

    private void loadFragment(Fragment fragment, boolean addToBackStack) {
        FragmentTransaction tx = getSupportFragmentManager().beginTransaction();
        tx.setCustomAnimations(android.R.anim.fade_in, android.R.anim.fade_out);
        tx.replace(R.id.fragment_container, fragment);
        if (addToBackStack) tx.addToBackStack(null);
        tx.commit();
    }

    /** Call from any Fragment to log out */
    public void logout() {
        sessionManager.clearSession();
        Intent intent = new Intent(this, LoginActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }

    @Override
    public void onBackPressed() {
        if (getSupportFragmentManager().getBackStackEntryCount() > 0) {
            getSupportFragmentManager().popBackStack();
            selectedNavId = R.id.nav_home;
            setNavSelected(R.id.nav_home);
        } else {
            super.onBackPressed();
        }
    }
}

package me.nethma.bookdiary;

import android.content.Intent;
import android.content.res.ColorStateList;
import android.graphics.drawable.GradientDrawable;
import android.os.Bundle;
import android.widget.FrameLayout;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.TextView;

import androidx.activity.EdgeToEdge;
import androidx.core.graphics.Insets;
import androidx.core.view.ViewCompat;
import androidx.core.view.WindowInsetsCompat;
import androidx.fragment.app.Fragment;
import androidx.fragment.app.FragmentContainerView;
import androidx.fragment.app.FragmentTransaction;

import me.nethma.bookdiary.utils.NotificationHelper;
import me.nethma.bookdiary.utils.NotificationScheduler;
import me.nethma.bookdiary.utils.SessionManager;
import me.nethma.bookdiary.utils.ThemePrefsManager;

public class MainActivity extends BaseActivity {

    // COLOR_ACTIVE is loaded from ThemePrefsManager at runtime
    private int COLOR_ACTIVE;
    private static final int COLOR_INACTIVE = 0xFF64748B;

    private FragmentContainerView fragmentContainer;
    private LinearLayout bottomNav;
    private SessionManager sessionManager;

    // Nav items
    private LinearLayout navHome, navSearch, navAdd, navDiary, navProfile;
    private ImageView icHome, icSearch, icDiary, icProfile;
    private TextView tvHome, tvSearch, tvAdd, tvDiary, tvProfile;

    // Add button specific views
    private FrameLayout addBtnBg;
    private ImageView icAdd;

    private int selectedNavId = R.id.nav_home;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        EdgeToEdge.enable(this);
        setContentView(R.layout.activity_main);

        // Load accent colour from prefs
        COLOR_ACTIVE = ThemePrefsManager.getAccentColor(this);

        fragmentContainer = findViewById(R.id.fragment_container);
        bottomNav         = findViewById(R.id.bottom_nav);
        sessionManager    = new SessionManager(this);

        // Apply insets
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.main), (v, insets) -> {
            Insets systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars());
            // Bottom nav: bottom padding = system nav bar
            bottomNav.setPadding(
                    bottomNav.getPaddingLeft(),
                    bottomNav.getPaddingTop(),
                    bottomNav.getPaddingRight(),
                    systemBars.bottom
            );
            // Fragment container: top = status bar, bottom = nav bar + bottom nav height
            fragmentContainer.setPadding(
                    systemBars.left,
                    systemBars.top,
                    systemBars.right,
                    systemBars.bottom + getResources().getDimensionPixelSize(R.dimen.bottom_nav_height)
            );
            return insets;
        });

        bindNavViews();
        applyAccentToAddButton(); // set accent circle on add button immediately

        // Create notification channels and schedule background workers
        NotificationHelper.createNotificationChannels(this);
        NotificationScheduler.scheduleAll(this);

        if (savedInstanceState == null) {
            loadFragment(new HomeFragment(), false);
        }
        setNavSelected(R.id.nav_home);

        navHome.setOnClickListener(v    -> selectTab(R.id.nav_home,    new HomeFragment()));
        navSearch.setOnClickListener(v  -> selectTab(R.id.nav_search,  new SearchFragment()));
        navAdd.setOnClickListener(v     -> selectTab(R.id.nav_add,     new AddFragment()));
        navDiary.setOnClickListener(v   -> selectTab(R.id.nav_diary,   new DiaryFragment()));
        navProfile.setOnClickListener(v -> selectTab(R.id.nav_profile, new ProfileFragment()));
    }

    @Override
    protected void onResume() {
        super.onResume(); // BaseActivity scans the full view tree
        // Refresh nav bar active colour (set programmatically, not via XML)
        COLOR_ACTIVE = ThemePrefsManager.getAccentColor(this);
        setNavSelected(selectedNavId);
        // Apply accent to the floating add button
        applyAccentToAddButton();
    }

    private void applyAccentToAddButton() {
        int accent = ThemePrefsManager.getAccentColor(this);

        // Recolor the FrameLayout background border stroke with accent/20
        if (addBtnBg != null && addBtnBg.getBackground() instanceof GradientDrawable) {
            GradientDrawable bg = (GradientDrawable) addBtnBg.getBackground().mutate();
            bg.setStroke(2, (accent & 0x00FFFFFF) | 0x33000000);
        }

        if (icAdd == null) return;

        // Draw an accent-colored circle as the ImageView background
        // and show only the white plus on top — this way accent changes are visible
        // without the plus disappearing (which happens when tinting the full circle+plus vector)
        GradientDrawable accentCircle = new GradientDrawable();
        accentCircle.setShape(GradientDrawable.OVAL);
        accentCircle.setColor(accent);
        icAdd.setBackground(accentCircle);
        icAdd.setPadding(10, 10, 10, 10);

        // Use a white-plus-only icon (no circle path) — tint cleared
        icAdd.setImageTintList(null);
        icAdd.setImageResource(R.drawable.ic_add_plus_white);
    }

    private void bindNavViews() {
        navHome    = findViewById(R.id.nav_home);
        navSearch  = findViewById(R.id.nav_search);
        navAdd     = findViewById(R.id.nav_add);
        navDiary   = findViewById(R.id.nav_diary);
        navProfile = findViewById(R.id.nav_profile);

        icHome    = findViewById(R.id.ic_home);
        icSearch  = findViewById(R.id.ic_search);
        icDiary   = findViewById(R.id.ic_diary);
        icProfile = findViewById(R.id.ic_profile);

        addBtnBg  = findViewById(R.id.add_btn_bg);
        icAdd     = findViewById(R.id.ic_add);

        tvHome    = findViewById(R.id.tv_home);
        tvSearch  = findViewById(R.id.tv_search);
        tvAdd     = findViewById(R.id.tv_add);
        tvDiary   = findViewById(R.id.tv_diary);
        tvProfile = findViewById(R.id.tv_profile);
    }

    private void selectTab(int navId, Fragment fragment) {
        if (selectedNavId == navId) return;
        selectedNavId = navId;
        setNavSelected(navId);
        loadFragment(fragment, true);
    }

    /** Update icon tints and label colors to reflect the selected tab */
    private void setNavSelected(int navId) {
        // Reset all to inactive
        icHome.setImageTintList(ColorStateList.valueOf(COLOR_INACTIVE));
        icSearch.setImageTintList(ColorStateList.valueOf(COLOR_INACTIVE));
        icDiary.setImageTintList(ColorStateList.valueOf(COLOR_INACTIVE));
        icProfile.setImageTintList(ColorStateList.valueOf(COLOR_INACTIVE));

        tvHome.setTextColor(COLOR_INACTIVE);
        tvSearch.setTextColor(COLOR_INACTIVE);
        tvAdd.setTextColor(COLOR_INACTIVE);
        tvDiary.setTextColor(COLOR_INACTIVE);
        tvProfile.setTextColor(COLOR_INACTIVE);

        // Activate selected
        if (navId == R.id.nav_home) {
            icHome.setImageTintList(ColorStateList.valueOf(COLOR_ACTIVE));
            tvHome.setTextColor(COLOR_ACTIVE);
        } else if (navId == R.id.nav_search) {
            icSearch.setImageTintList(ColorStateList.valueOf(COLOR_ACTIVE));
            tvSearch.setTextColor(COLOR_ACTIVE);
        } else if (navId == R.id.nav_add) {
            tvAdd.setTextColor(COLOR_ACTIVE);
            // Add icon is always primary color (filled svg), no tint needed
        } else if (navId == R.id.nav_diary) {
            icDiary.setImageTintList(ColorStateList.valueOf(COLOR_ACTIVE));
            tvDiary.setTextColor(COLOR_ACTIVE);
        } else if (navId == R.id.nav_profile) {
            icProfile.setImageTintList(ColorStateList.valueOf(COLOR_ACTIVE));
            tvProfile.setTextColor(COLOR_ACTIVE);
        }
    }

    private void loadFragment(Fragment fragment, boolean addToBackStack) {
        FragmentTransaction tx = getSupportFragmentManager().beginTransaction();
        tx.setCustomAnimations(android.R.anim.fade_in, android.R.anim.fade_out);
        tx.replace(R.id.fragment_container, fragment);
        if (addToBackStack) tx.addToBackStack(null);
        tx.commit();
    }

    /**
     * Called from HomeFragment's filter button.
     * Opens SearchFragment pre-filled with the current home search query.
     */
    public void navigateToSearch(String initialQuery) {
        selectedNavId = R.id.nav_search;
        setNavSelected(R.id.nav_search);
        loadFragment(SearchFragment.newInstance(initialQuery), true);
    }

    /** Call from any Fragment to log out */
    public void logout() {
        sessionManager.clearSession();
        Intent intent = new Intent(this, LoginActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }

    @Override
    public void onBackPressed() {
        if (getSupportFragmentManager().getBackStackEntryCount() > 0) {
            getSupportFragmentManager().popBackStack();
            selectedNavId = R.id.nav_home;
            setNavSelected(R.id.nav_home);
        } else {
            super.onBackPressed();
        }
    }
}

package me.nethma.bookdiary;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;

public class SearchFragment extends BaseFragment {
    @Nullable @Override
    public View onCreateView(@NonNull LayoutInflater inflater,
                             @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        return inflater.inflate(R.layout.fragment_search, container, false);
